refsection.programlisting:
// load the database containing the GDP for 25 countries in the OECD over the period 1963-2003
load(GROCERDIR+'/macros/grocer/db/gdpan_oecd.dat');
// retrieve the names of all variables in database
listvar=dblist(GROCERDIR+'/macros/grocer/db/gdpan_oecd.dat')

res = Moon_Perron('log('+listvar+')','kmax=5','t_order=0','kernel=qs','bandwidth=n','criteria=BIC3')
// This example (taken from Moon_Perron_d()) provides the Moon and Perron test for the log of gdp of 25 OECD countries,
// with individual constants but no trends ('t_order=0'), the maximum # of factors allowed set to 5 ('kmax=5'),
// the number of factors determined by the criteria 'AIC1' proposed by Bai an Ng ('criteria=AIC1'),
// the Newey-West bandwidth ('bandwidth=n') and the Quadratic Spectral kernel ('kernel=b').

res = Moon_Perron('log('+listvar+')','kmax=5','t_order=0','kernel=b','bandwidth=n','criteria=AIC1')
// This Example does the same but with the criteria 'AIC1' proposed by Bai an Ng ('criteria=AIC1') and the Barlett kernel ('kernel=b').
